namespace sv_4b47d155e2db4488b741746457539c45;

// Immutable records for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(FullName) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone) &&
        !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Company) &&
        !string.IsNullOrWhiteSpace(Title) &&
        StartDate.HasValue;

    public WorkEntry ToRecord() => new(Company, Title, StartDate!.Value, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Name) &&
        !string.IsNullOrWhiteSpace(Relationship) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i + 1;
            var state = GetStepState(stepIndex);
            <li class="step-item text-center flex-fill @state" @onclick="() => HandleClick(stepIndex)">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle @GetCircleClass(state)">
                    @if (state == "completed")
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@stepIndex</span>
                    }
                </div>
                <small class="step-label d-none d-md-block">@StepNames[i]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private string GetCircleClass(string state) => state switch
    {
        "active" => "bg-primary text-white",
        "completed" => "bg-success text-white",
        _ => "bg-secondary text-white opacity-50"
    };

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.dimmed {
    cursor: default;
}

.step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.85rem;
    font-weight: 600;
    transition: all 0.2s ease;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: var(--bs-success);
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, var(--bs-primary) 50%, #dee2e6 50%);
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Personal Information</h4>

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" />
            @if (emailError is not null)
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"></textarea>
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
                @if (isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Next
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (!Model.IsValid())
        {
            validationError = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isEmailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Entry="Entries[index]" Index="index"
                           CanRemove="Entries.Count > 1"
                           OnRemove="RemoveEntry" />
        }

        <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;
        if (Entries.Any(e => !e.IsValid()))
        {
            validationError = "Please fill in all required fields for each position.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="mb-0">Reference @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync(Index)">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<int> OnRemove { get; set; }
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">References</h4>
        <p class="text-muted small">Please provide 2–3 professional references.</p>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceForm Reference="References[index]" Index="index"
                           CanRemove="References.Count > 2"
                           OnRemove="RemoveReference" />
        }

        @if (References.Count < 3)
        {
            <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;
        if (References.Any(r => !r.IsValid()))
        {
            validationError = "Please fill in all required fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Cover Letter</h4>

        <div class="mb-2">
            <textarea class="form-control" rows="10" maxlength="@MaxLength"
                      @bind="CoverLetter" @bind:event="oninput"
                      @bind:after="NotifyChanged"
                      placeholder="Write your cover letter here..."></textarea>
        </div>
        <div class="text-muted small text-end mb-3">
            @(CoverLetter?.Length ?? 0) / @MaxLength characters
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);

    private async Task HandleNext()
    {
        validationError = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            validationError = "Please write a cover letter.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

@if (ApplicationId.HasValue)
{
    <div class="card border-success">
        <div class="card-body text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">✓</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@ApplicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    </div>
}
else
{
    <div class="card">
        <div class="card-body">
            <h4 class="card-title mb-4">Review Your Application</h4>

            @* Personal Info *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
                </div>
                <dl class="row mb-0">
                    <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
                </dl>
            </div>
            <hr />

            @* Work History *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1 small">@entry.Description</p>
                        }
                    </div>
                }
            </div>
            <hr />

            @* References *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
                </div>
                @foreach (var reference in References)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@reference.Name</strong> — @reference.Relationship<br />
                        <small class="text-muted">@reference.Email · @reference.Phone</small>
                    </div>
                }
            </div>
            <hr />

            @* Cover Letter *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
                </div>
                <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (errorMessage is not null)
            {
                <div class="alert alert-danger py-2">@errorMessage</div>
            }

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="OnBack">Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Submit Application
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEdit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

