{"path": "/tmp/sv-4b47d155e2db4488b741746457539c45/Components/Pages/Apply/PersonalInfoStep.razor", "file_text": "@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Personal Information</h4>

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" />
            @if (emailError is not null)
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"></textarea>
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
                @if (isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Next
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? validationError;
    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (!Model.IsValid())
        {
            validationError = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isEmailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}
"}

{"path": "/tmp/sv-4b47d155e2db4488b741746457539c45/Components/Pages/Apply/WorkHistoryStep.razor", "file_text": "@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Work History</h4>

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryForm Entry="Entries[index]" Index="index"
                           CanRemove="Entries.Count > 1"
                           OnRemove="RemoveEntry" />
        }

        <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;
        if (Entries.Any(e => !e.IsValid()))
