        }
        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-4b47d155e2db4488b741746457539c45/Components/Pages/Apply/ReferencesStep.razor", "file_text": "@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">References</h4>
        <p class="text-muted small">Please provide 2–3 professional references.</p>

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceForm Reference="References[index]" Index="index"
                           CanRemove="References.Count > 2"
                           OnRemove="RemoveReference" />
        }

        @if (References.Count < 3)
        {
            <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        validationError = null;
        if (References.Any(r => !r.IsValid()))
        {
            validationError = "Please fill in all required fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-4b47d155e2db4488b741746457539c45/Components/Pages/Apply/CoverLetterStep.razor", "file_text": "@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<div class="card">
    <div class="card-body">
        <h4 class="card-title mb-3">Cover Letter</h4>

        <div class="mb-2">
            <textarea class="form-control" rows="10" maxlength="@MaxLength"
                      @bind="CoverLetter" @bind:event="oninput"
                      @bind:after="NotifyChanged"
                      placeholder="Write your cover letter here..."></textarea>
        </div>
        <div class="text-muted small text-end mb-3">
            @(CoverLetter?.Length ?? 0) / @MaxLength characters
        </div>

        @if (validationError is not null)
        {
            <div class="alert alert-danger py-2">@validationError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next</button>
        </div>
    </div>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);

    private async Task HandleNext()
    {
        validationError = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            validationError = "Please write a cover letter.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-4b47d155e2db4488b741746457539c45/Components/Pages/Apply/ReviewStep.razor", "file_text": "@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

@if (ApplicationId.HasValue)
{
    <div class="card border-success">
        <div class="card-body text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">✓</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@ApplicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    </div>
}
else
{
    <div class="card">
        <div class="card-body">
            <h4 class="card-title mb-4">Review Your Application</h4>

            @* Personal Info *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Personal Information</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
                </div>
                <dl class="row mb-0">
                    <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
                </dl>
            </div>
            <hr />

            @* Work History *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Work History</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@entry.Title</strong> at @entry.Company<br />
                        <small class="text-muted">
                            @entry.StartDate?.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1 small">@entry.Description</p>
                        }
                    </div>
                }
            </div>
            <hr />

            @* References *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">References</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
                </div>
                @foreach (var reference in References)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@reference.Name</strong> — @reference.Relationship<br />
                        <small class="text-muted">@reference.Email · @reference.Phone</small>
                    </div>
                }
            </div>
            <hr />

            @* Cover Letter *@
            <div class="mb-4">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="mb-0">Cover Letter</h5>
                    <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
                </div>
                <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
            </div>

            @if (errorMessage is not null)
            {
                <div class="alert alert-danger py-2">@errorMessage</div>
            }

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="OnBack">Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Submit Application
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEdit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private async Task HandleSubmit()
    {
        errorMessage = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
    }
}
"}

