@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex justify-content-between list-unstyled mb-0 position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i + 1;
            var state = GetStepState(stepIndex);
            <li class="step-item text-center flex-fill @state" @onclick="() => HandleClick(stepIndex)">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle @GetCircleClass(state)">
                    @if (state == "completed")
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@stepIndex</span>
                    }
                </div>
                <small class="step-label d-none d-md-block">@StepNames[i]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private string GetCircleClass(string state) => state switch
    {
        "active" => "bg-primary text-white",
        "completed" => "bg-success text-white",
        _ => "bg-secondary text-white opacity-50"
    };

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

