.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.dimmed {
    cursor: default;
}

.step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.85rem;
    font-weight: 600;
    transition: all 0.2s ease;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: var(--bs-success);
}

.step-item.active:not(:last-child)::after {
    background: linear-gradient(to right, var(--bs-primary) 50%, #dee2e6 50%);
}

