@page "/apply"
@rendermode InteractiveServer
@namespace sv_4b47d155e2db4488b741746457539c45.Components.Pages.Apply
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo" ApplicationService="ApplicationService"
                              OnNext="() => AdvanceTo(2)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => AdvanceTo(3)" OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => AdvanceTo(4)" OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="() => AdvanceTo(5)" OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo" WorkEntries="workEntries"
                        References="references" CoverLetter="coverLetter"
                        IsSubmitting="isSubmitting" ApplicationId="applicationId"
                        OnEdit="GoToStep" OnSubmit="SubmitApplication" OnBack="() => GoToStep(4)" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = [];
    private bool isSubmitting;
    private int? applicationId;

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void AdvanceTo(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );
            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

